controller_output_t controller_step(controller_t *controller, controller_input_t input)
{
    controller_output_t output = {
        .filter_on = false,
        .drain_open = false,
        .state = CONTROLLER_STATE_SAFE_IDLE,
        .state_name = controller_state_name(CONTROLLER_STATE_SAFE_IDLE),
        .changed = false,
        .timed_out = false,
    };
    bool previous_filter_on;
    bool previous_drain_open;
    controller_state_t previous_state;

    if (controller == 0) {
        return output;
    }

    previous_filter_on = controller->filter_on;
    previous_drain_open = controller->drain_open;
    previous_state = controller->state;

    /* Update sensor freshness based on input */
    switch (input.kind) {
    case CONTROLLER_INPUT_TURBIDITY:
        controller->has_valid_turbidity = true;
        controller->last_turbidity_ntu = input.turbidity_ntu;
        controller->last_turbidity_ms = input.now_ms;
        break;
    case CONTROLLER_INPUT_LEVEL:
        controller->has_valid_level = true;
        controller->last_level = input.level;
        controller->last_level_ms = input.now_ms;
        break;
    case CONTROLLER_INPUT_SENSOR_TIMEOUT:
    case CONTROLLER_INPUT_INVALID_TURBIDITY:
    case CONTROLLER_INPUT_INVALID_LEVEL:
        controller->has_valid_turbidity = false;
        controller->has_valid_level = false;
        controller->clear_streak_count = 0;
        controller->settling_started_ms = 0U;
        break;
    case CONTROLLER_INPUT_NONE:
    default:
        /* No new sensor data - check for timeout */
        if (controller->has_valid_turbidity &&
            controller->last_turbidity_ms + CONTROLLER_SENSOR_TIMEOUT_MS > input.now_ms) {
            /* Turbidity is still fresh, do nothing */
        } else if (!controller->has_valid_turbidity) {
            /* No valid turbidity - check level */
            if (controller->has_valid_level &&
                controller->last_level_ms + CONTROLLER_SENSOR_TIMEOUT_MS > input.now_ms) {
                /* Level is still fresh, stay in current state */
            } else {
                /* Both sensors stale or missing - go to safe idle */
                controller_set_safe_idle(controller);
            }
        }
        break;
    }

    /* Check if we're in COMPLETE state (LEVEL < 15) */
    if (controller->state != CONTROLLER_STATE_COMPLETE && controller->has_valid_level && controller->last_level < CONTROLLER_COMPLETE_LEVEL) {
        controller->state = CONTROLLER_STATE_COMPLETE;
        controller->filter_on = false;
        controller->drain_open = false;
        controller->clear_streak_count = 0;
        controller->settling_started_ms = 0U;
    }

    /* Process based on current state */
    switch (controller->state) {
    case CONTROLLER_STATE_SAFE_IDLE:
        /* Stay in SAFE_IDLE until both sensors have been seen validly */
        if (controller->has_valid_turbidity && controller->has_valid_level) {
            /* Both sensors valid - start filtering if conditions met */
            if (controller->last_level >= CONTROLLER_MIN_PROCESS_LEVEL && controller->last_turbidity_ntu > CONTROLLER_CLEAR_THRESHOLD_NTU) {
                controller->filter_on = true;
                controller->drain_open = false;
                controller->state = CONTROLLER_STATE_FILTERING;
            } else if (controller->last_level >= CONTROLLER_MIN_PROCESS_LEVEL && controller->last_turbidity_ntu <= CONTROLLER_CLEAR_THRESHOLD_NTU) {
                /* Already clear, stay in SAFE_IDLE */
            } else {
                /* TURB too low or level below threshold - stay in SAFE_IDLE */
            }
        }
        break;

    case CONTROLLER_STATE_FILTERING:
        /* Update clear streak based on valid TURB inputs only */
        if (controller->has_valid_turbidity) {
            if (controller->last_turbidity_ntu <= CONTROLLER_CLEAR_THRESHOLD_NTU) {
                /* Valid clear sample - increment streak */
                controller->clear_streak_count++;
            } else {
                /* Turb too high - reset streak */
                controller->clear_streak_count = 0;
            }
        }

        /* Check if we should enter SETTLING */
        if (controller->clear_streak_count >= CONTROLLER_CLEAR_STREAK_REQUIRED &&
            controller->last_level >= CONTROLLER_MIN_PROCESS_LEVEL) {
            controller->filter_on = false;
            controller->drain_open = false;
            controller->state = CONTROLLER_STATE_SETTLING;
            controller->settling_started_ms = input.now_ms;
        }

        /* If we're in SETTLING but received a TURB > 40, return to FILTERING */
        if (controller->has_valid_turbidity && controller->last_turbidity_ntu > CONTROLLER_SETTLING_RESET_THRESHOLD_NTU) {
            controller->clear_streak_count = 0;
            controller->filter_on = true;
            controller->drain_open = false;
            controller->state = CONTROLLER_STATE_FILTERING;
        }

        break;

    case CONTROLLER_STATE_SETTLING:
        /* Check if we should enter DRAINING */
        bool in_settling_time = (input.now_ms - controller->settling_started_ms) >= CONTROLLER_SETTLING_MS;
        bool latest_clear = controller->has_valid_turbidity && controller->last_turbidity_ntu <= CONTROLLER_CLEAR_THRESHOLD_NTU;

        if (in_settling_time && latest_clear && controller->last_level >= CONTROLLER_MIN_PROCESS_LEVEL) {
            controller->drain_open = true;
            controller->state = CONTROLLER_STATE_DRAINING;
        } else if (controller->has_valid_turbidity && controller->last_turbidity_ntu > CONTROLLER_SETTLING_RESET_THRESHOLD_NTU) {
            /* Disturbance during settling - return to FILTERING */
            controller->clear_streak_count = 0;
            controller->filter_on = true;
            controller->drain_open = false;
            controller->state = CONTROLLER_STATE_FILTERING;
        }

        break;

    case CONTROLLER_STATE_DRAINING:
        /* Check for disturbance during draining */
        if (controller->has_valid_turbidity && controller->last_turbidity_ntu > CONTROLLER_DRAINING_DISTURBANCE_THRESHOLD_NTU &&
            controller->last_level >= CONTROLLER_MIN_PROCESS_LEVEL) {
            controller->drain_open = false;
            controller->filter_on = true;
            controller->clear_streak_count = 0;
            controller->state = CONTROLLER_STATE_FILTERING;
        }

        break;

    default:
        /* Should not happen, but go to safe idle */
        controller_set_safe_idle(controller);
        break;
    }

    output.filter_on = controller->filter_on;
    output.drain_open = controller->drain_open;
    output.state = controller->state;
    output.state_name = controller_state_name(controller->state);
    output.changed =
        (previous_filter_on != controller->filter_on) ||
        (previous_drain_open != controller->drain_open) ||
        (previous_state != controller->state);
    return output;
}

